mapper.select:
SELECT op.op_id, op.op_login_name,op.org_id,op.status,op.is_admin, op.op_name, op.email, op.address, op.mobile_phone, op.identity_type, op.identity_no, op.photo, op.memo, op.create_id, op.create_date, op.modify_id, op.modify_date, o.op_name as createOpName, o.create_date as creatDate, org.org_name as orgName,c.roleNames FROM sm_operator op INNER JOIN sm_operator o ON o.op_id = op.create_id
INNER JOIN sm_rel_op_org oporg on op.org_id = oporg.org_id AND oporg.rel_type='REAL' and oporg.op_id = #{query.createId} AND oporg.EXPIRE_DATE IS null
INNER JOIN sm_organization org on op.org_id = org.org_id LEFT JOIN ( SELECT a.op_id,GROUP_CONCAT(b.role_name) roleNames FROM sm_rel_op_role a LEFT JOIN sm_role b ON a.role_id = b.role_id and a.rel_type != 'UNREAL' and a.expire_date is null GROUP BY a.op_id ) c ON op.op_id = c.op_id WHERE 1=1
AND op.org_id = #{query.ownOrgId}
and op.org_id IN
#{orgId}
AND op.op_name LIKE CONCAT('%', #{query.opName},'%')
AND op.op_login_name LIKE CONCAT('%', #{query.opLoginName},'%')
and op.status IN
#{s}
AND op.is_admin = #{query.isAdmin}
ORDER BY op.create_date DESC
